"""Utilities for converting JSONPath expressions to JSON Schema."""

import json
import re
from typing import List, Optional


def _parse_jsonpath(path: str) -> List[Optional[str]]:
    """Parse a JSONPath string into a list of segments.

    Each segment is either:
    - A ``str``: an object property key (from ``.key`` or ``['key']`` notation).
    - ``None``: an array access (wildcard ``[*]`` or a numeric index ``[n]``).

    Args:
        path: A JSONPath string starting with ``'$'``.

    Returns:
        An ordered list of path segments (possibly empty for a bare ``'$'``).

    Raises:
        ValueError: If the path is syntactically invalid or uses unsupported
            operators (e.g. recursive-descent ``'..'``, filter expressions
            ``[?(...)]``).
    """
    if not path.startswith("$"):
        raise ValueError(f"JSONPath must start with '$', got: {path!r}")

    segments: List[Optional[str]] = []
    i = 1  # skip the leading '$'

    while i < len(path):
        ch = path[i]

        if ch == ".":
            i += 1
            if i >= len(path):
                raise ValueError("Unexpected end of JSONPath after '.'")
            if path[i] == ".":
                raise ValueError(
                    "Recursive-descent operator ('..') is not supported. "
                    "Use explicit key segments instead."
                )
            # dot-notation key: must match a valid identifier
            m = re.match(r"([A-Za-z_$][A-Za-z0-9_$]*)", path[i:])
            if not m:
                raise ValueError(
                    f"Expected an identifier after '.', got {path[i : i + 10]!r}"
                )
            segments.append(m.group(1))
            i += len(m.group(1))

        elif ch == "[":
            i += 1  # skip '['
            if i >= len(path):
                raise ValueError("Unexpected end of JSONPath inside '['")

            if path[i] == "*":
                # wildcard: [*]
                i += 1
                if i >= len(path) or path[i] != "]":
                    raise ValueError("Expected ']' after '[*'")
                segments.append(None)
                i += 1  # skip ']'

            elif path[i] in ('"', "'"):
                # bracket-notation string key: ['key'] or ["key"]
                quote = path[i]
                i += 1
                end = path.find(quote, i)
                if end == -1:
                    raise ValueError("Unterminated string in bracket notation")
                key = path[i:end]
                i = end + 1  # skip closing quote
                if i >= len(path) or path[i] != "]":
                    raise ValueError("Expected ']' after bracket-notation key")
                segments.append(key)
                i += 1  # skip ']'

            elif path[i].isdigit():
                # numeric index: [0], [1], … — treated as generic array access
                end = path.find("]", i)
                if end == -1:
                    raise ValueError("Unterminated '[' in JSONPath")
                idx_str = path[i:end]
                if not idx_str.isdigit():
                    raise ValueError(f"Invalid array index: {idx_str!r}")
                segments.append(None)
                i = end + 1  # skip past ']'

            else:
                raise ValueError(
                    f"Unexpected character inside '[': {path[i]!r}. "
                    "Filter expressions and other advanced operators are not supported."
                )

        else:
            raise ValueError(
                f"Unexpected character at position {i} in JSONPath: {path[i]!r}"
            )

    return segments


def jsonpath_to_json_schema(path: str) -> str:
    """Convert a JSONPath expression to a JSON Schema string.

    The resulting schema validates any JSON document that contains the
    structure implied by *path*.  Intermediate object nodes are required to
    carry the specified key; array nodes require their items to satisfy the
    rest of the path.

    Examples::

        >>> jsonpath_to_json_schema("$.author")
        '{"type": "object", "properties": {"author": {}}, "required": ["author"]}'

        >>> import json
        >>> json.loads(jsonpath_to_json_schema("$.store.book[*].author"))
        {
            "type": "object",
            "properties": {
                "store": {
                    "type": "object",
                    "properties": {
                        "book": {
                            "type": "array",
                            "items": {
                                "type": "object",
                                "properties": {"author": {}},
                                "required": ["author"]
                            }
                        }
                    },
                    "required": ["book"]
                }
            },
            "required": ["store"]
        }

    Args:
        path: A JSONPath expression starting with ``'$'``.

    Returns:
        A JSON Schema string (serialised with :func:`json.dumps`).

    Raises:
        ValueError: If *path* is syntactically invalid or uses unsupported
            operators.
    """
    segments = _parse_jsonpath(path)

    if not segments:
        # Bare '$' — any JSON value is acceptable.
        return json.dumps({})

    # Build the schema from the innermost (rightmost) segment outward.
    # We start with an empty schema ``{}`` for the leaf value (unconstrained).
    schema: dict = {}

    for segment in reversed(segments):
        if segment is None:
            # Array segment: the current schema describes the element type.
            schema = {"type": "array", "items": schema}
        else:
            # Object-key segment: the current schema describes the value type.
            schema = {
                "type": "object",
                "properties": {segment: schema},
                "required": [segment],
            }

    return json.dumps(schema)

def dispatch_structural_tag(self, key_string: str) -> Optional[BaseGrammarObject]:
    return self._not_supported("structural_tag", key_string)

def dispatch_json_path(self, key_string: str) -> Optional[BaseGrammarObject]:
    return self._not_supported("json_path", key_string)

def _init_value_dispatch(
    self, key: Tuple[str, str], require_reasoning: bool
) -> Optional[BaseGrammarObject]:
    s = time.perf_counter()
    key_type, key_string = key
    if key_type == "json":
        grammar = self.dispatch_json(key_string)
    elif key_type == "regex":
        grammar = self.dispatch_regex(key_string)
    elif key_type == "ebnf":
        grammar = self.dispatch_ebnf(key_string)
    elif key_type == "structural_tag":
        grammar = self.dispatch_structural_tag(key_string)
    elif key_type == "structural_pattern":
        grammar = self.dispatch_structural_pattern(key_string)
    elif key_type == "structural_pattern_v2":
        grammar = self.dispatch_structural_pattern_v2(key_string)
    elif key_type == "json_path":
        grammar = self.dispatch_json_path(key_string)
    else:
        grammar = self.dispatch_fallback(key_type, key_string)

    if grammar is not None and grammar.grammar_stats is not None:
        grammar.grammar_stats.compilation_time = time.perf_counter() - s
